INSERT INTO "media" ("id", "title", "description", "synopsis", "posterUrl", "backdropUrl", "trailerUrl", "releaseYear", "director", "cast", "duration", "language", "country", "contentRating", "mediaType", "streamingPlatform", "price", "priceType", "isPublished", "viewCount", "averageRating", "createdAt", "updatedAt") VALUES ('19', 'The Crown', 'Follows the political rivalries and romance of Queen Elizabeth II''s reign and the events that shaped the second half of the 20th century.', 'Follows the political rivalries and romance of Queen Elizabeth II''s reign and the events that shaped the second half of the 20th century.', 'https://image.tmdb.org/t/p/w500/1Q2F2Cw5yYC9pqhIwpXJqNqnL6P.jpg', 'https://image.tmdb.org/t/p/original/hvFmhpMdsg6vqFqW4X5eXp6PqJ1.jpg', NULL, 2016, 'Peter Morgan', ARRAY['Claire Foy', 'Olivia Colman', 'Imelda Staunton', 'Matt Smith']::text[], 120, 'English', 'USA', 'PG-13', 'SERIES'::"MediaType", 'Netflix', 9.99, 'PREMIUM'::"PriceType", true, 20, 8.5, NOW(), NOW());
INSERT INTO "media" ("id", "title", "description", "synopsis", "posterUrl", "backdropUrl", "trailerUrl", "releaseYear", "director", "cast", "duration", "language", "country", "contentRating", "mediaType", "streamingPlatform", "price", "priceType", "isPublished", "viewCount", "averageRating", "createdAt", "updatedAt") VALUES ('20', 'Barbie', 'Barbie and Ken are having the time of their lives in the colorful and seemingly perfect world of Barbie Land. However, when they get to go to the real world, they soon discover the problems with being human.', 'Barbie and Ken are having the time of their lives in the colorful and seemingly perfect world of Barbie Land. However, when they get to go to the real world, they soon discover the problems with being human.', 'https://image.tmdb.org/t/p/w500/iuFNMS8U5cJU6lYBsAgZGa802G7.jpg', 'https://image.tmdb.org/t/p/original/ctMserH8g2SeOAnCw5gFjdQF8mo.jpg', NULL, 2023, 'Greta Gerwig', ARRAY['Margot Robbie', 'Ryan Gosling', 'America Ferrera', 'Kate McKinnon']::text[], 120, 'English', 'USA', 'PG-13', 'MOVIE'::"MediaType", 'HBO Max', 9.99, 'PREMIUM'::"PriceType", true, 20, 7.4, NOW(), NOW());
