INSERT INTO "reviews" ("id", "rating", "content", "tags", "isSpoiler", "status", "likesCount", "userId", "mediaId", "createdAt", "updatedAt") VALUES ('r1', 9.5, 'A masterful epic that surpasses the original in every way. Villeneuve has crafted something truly special - the cinematography, score, and performances are all outstanding. This is why we go to the movies.', ARRAY['masterpiece', 'must-see']::text[], false, 'APPROVED'::"ReviewStatus", 342, 'u1', '1', '2024-03-15T10:30:00Z', NOW());
INSERT INTO "reviews" ("id", "rating", "content", "tags", "isSpoiler", "status", "likesCount", "userId", "mediaId", "createdAt", "updatedAt") VALUES ('r2', 9, 'Visually breathtaking. The sandworm sequences alone are worth the price of admission. The political intrigue is woven perfectly into the action. Can''t wait for the next installment!', ARRAY['visually-stunning', 'epic']::text[], false, 'APPROVED'::"ReviewStatus", 198, 'u2', '1', '2024-03-18T14:20:00Z', NOW());
INSERT INTO "reviews" ("id", "rating", "content", "tags", "isSpoiler", "status", "likesCount", "userId", "mediaId", "createdAt", "updatedAt") VALUES ('r3', 9.2, 'This show defined a generation of television. The blend of 80s nostalgia, horror, and coming-of-age drama is simply perfect. Every season brings something new and terrifying.', ARRAY['nostalgic', 'binge-worthy']::text[], true, 'APPROVED'::"ReviewStatus", 567, 'u3', '3', '2024-01-22T09:15:00Z', NOW());
INSERT INTO "reviews" ("id", "rating", "content", "tags", "isSpoiler", "status", "likesCount", "userId", "mediaId", "createdAt", "updatedAt") VALUES ('r4', 10, 'The greatest television show ever made. Period. Bryan Cranston''s transformation from Mr. Chips to Scarface is the finest acting performance I''ve ever witnessed. Every season tops the last.', ARRAY['classic', 'masterpiece', 'intense']::text[], false, 'APPROVED'::"ReviewStatus", 892, 'u4', '5', '2024-02-10T16:45:00Z', NOW());
INSERT INTO "reviews" ("id", "rating", "content", "tags", "isSpoiler", "status", "likesCount", "userId", "mediaId", "createdAt", "updatedAt") VALUES ('r5', 9, 'Nolan has created a haunting portrait of genius and its consequences. Murphy disappears into the role completely. The Trinity test sequence is one of the most tense scenes in cinema history.', ARRAY['thought-provoking', 'intense']::text[], false, 'APPROVED'::"ReviewStatus", 445, 'u5', '4', '2024-04-05T11:00:00Z', NOW());
INSERT INTO "reviews" ("id", "rating", "content", "tags", "isSpoiler", "status", "likesCount", "userId", "mediaId", "createdAt", "updatedAt") VALUES ('r6', 10, 'Heath Ledger''s Joker remains the gold standard for comic book villains. This transcends the superhero genre and stands as one of the greatest crime dramas ever made.', ARRAY['classic', 'iconic']::text[], false, 'APPROVED'::"ReviewStatus", 1023, 'u6', '16', '2024-01-08T08:30:00Z', NOW());
INSERT INTO "comments" ("id", "content", "likesCount", "userId", "reviewId", "parentId", "createdAt", "updatedAt") VALUES ('c1', 'Couldn''t agree more! The sound design in IMAX was incredible.', 0, 'u2', 'r1', NULL, '2024-03-16T12:00:00Z', NOW());
INSERT INTO "comments" ("id", "content", "likesCount", "userId", "reviewId", "parentId", "createdAt", "updatedAt") VALUES ('c2', 'Have you read the books? The adaptation is remarkably faithful.', 0, 'u3', 'r1', NULL, '2024-03-16T14:30:00Z', NOW());
INSERT INTO "comments" ("id", "content", "likesCount", "userId", "reviewId", "parentId", "createdAt", "updatedAt") VALUES ('c3', 'Yes! Frank Herbert would be proud. Villeneuve really understands the source material.', 0, 'u1', 'r1', 'c2', '2024-03-16T15:45:00Z', NOW());
INSERT INTO "comments" ("id", "content", "likesCount", "userId", "reviewId", "parentId", "createdAt", "updatedAt") VALUES ('c4', 'I just finished season 4 and I''m completely speechless. This show is on another level.', 0, 'u5', 'r4', NULL, '2024-02-11T10:00:00Z', NOW());
INSERT INTO "comments" ("id", "content", "likesCount", "userId", "reviewId", "parentId", "createdAt", "updatedAt") VALUES ('c5', 'The interrogation scene between Batman and Joker is pure cinematic perfection.', 0, 'u4', 'r6', NULL, '2024-01-09T09:00:00Z', NOW());
